import './CounterBody.scss';

import React, { forwardRef } from 'react';

import { classNames } from '../../../helpers/classnames';
import { BadgeContent } from '../BadgeContent';
import type { CounterProps } from '../Counter.types';
import { isNumber } from '../utils';

export const CounterBody = forwardRef<HTMLDivElement, CounterProps>(
	({ children, className, count, warning, hideBadgeContent, error, size, ...rest }, ref) => {
		const rootClassName = classNames('dsb-counter-root', className);

		return (
			<div data-testid="CounterBody" {...rest} className={rootClassName} ref={ref}>
				{children}

				{(isNumber(count) || warning) && (
					<BadgeContent
						count={count}
						error={error}
						warning={warning}
						hideBadgeContent={hideBadgeContent}
						size={size}
						stanalone={!children}
					/>
				)}
			</div>
		);
	},
);
